With.Cte:

				SELECT {{
							Fields
								-Dimension: PointsOfSale 
									--Table: PointsOfSaleCte
								-Dimension: Products 
									--Table: ProductsCte
								-WithComma
                	   }}			   
					   {{
							IfRequest
								-Expression: SellingFrequency
									--MAX(SalesDecelerations.SellingFrequency) AS SellingFrequency									
								-Expression: Limit
									--MAX(SalesDecelerations.Limit) AS Limit									
								-Expression: ActualStock
									--SUM(SalesDecelerations.ActualStock) AS ActualStock									
								-Expression: LastSaleDays
									--MAX(SalesDecelerations.LastSaleDays) AS LastSaleDays									
								-Expression: SellThrough
									--SUM(SalesDecelerations.SellThrough) AS SellThrough									
								-Expression: PotentiallyLostSales
									--SUM(SalesDecelerations.PotentiallyLostSales) AS PotentiallyLostSales
						}}						   
					FROM Fact.SalesDecelerations
					{{
                		InnerJoin 
                			-Dimension: PointsOfSale 
                				--Table: PointsOfSaleCte
							-Table: SalesDecelerations
							-On:PointOfSaleId-PointOfSaleId
					}}
	            	{{
	            		InnerJoin 
	            			-Dimension: Products 
	            				--Table: ProductsCte
							-Table: SalesDecelerations
							-On: ProductId-ProductId
	            	}}
					{{
                		GroupBy
                			-Dimension: PointsOfSale 
                				--Table: PointsOfSaleCte
	            			-Dimension: Products 
	            				--Table: ProductsCte
	            	}}
